cat << 'EOF' > patch-dashboard.mjs
import fs from 'fs';

const serverFile = 'scripts/dashboard/server.mjs';
let serverCode = fs.readFileSync(serverFile, 'utf8');

if (!serverCode.includes('/api/learning/status')) {
  const handlerCode = `
// ─── Learning API handlers ───────────────────────────────────────────────────

async function handleLearningStatus() {
  const date = new Date().toISOString().slice(0, 10);
  const dailyPath = join(getVaultRoot(), '11_Learning', '01_Daily', \`\${date}.md\`);

  if (!existsSync(dailyPath)) {
    return { status: 'Needs Daily Note', date };
  }

  const dailyNote = await readNote(dailyPath);
  const dailyCheckStatus = dailyNote.data.daily_check_status ?? 'Pending';
  const wildcardStatus = dailyNote.data.wildcard_status ?? 'Locked';

  if (dailyCheckStatus !== 'Completed' && dailyCheckStatus !== 'Complete') {
    return { status: 'Pending Knowledge Lock', date, dailyCheckStatus };
  }

  return { status: 'Wildcard Active', date, dailyCheckStatus, wildcardStatus };
}

async function handleLearningScaffold(body) {
  const command = 'learning-session';
  const args = [command];
  if (body.topic) args.push('--topic', \`"\${body.topic}"\`);
  if (body.topicId) args.push('--topic-id', body.topicId);

  const jobId = makeJobId();
  const proc = spawn('node', ['run.mjs', ...args], {
    cwd: SCRIPTS_DIR,
    shell: true,
    env: { ...process.env },
  });

  const job = { process: proc, buffer: [], listeners: new Set(), exitCode: null };
  jobs.set(jobId, job);

  function pushLine(text, stream) {
    const line = JSON.stringify({ text: text.replace(/\\n$/, ''), stream });
    job.buffer.push(line);
    for (const send of job.listeners) send(\`event: line\\ndata: \${line}\\n\\n\`);
  }

  proc.stdout.on('data', chunk => pushLine(chunk.toString(), 'stdout'));
  proc.stderr.on('data', chunk => pushLine(chunk.toString(), 'stderr'));

  proc.on('exit', code => {
    job.exitCode = code ?? 0;
    const exitMsg = JSON.stringify({ code: job.exitCode });
    for (const send of job.listeners) send(\`event: exit\\ndata: \${exitMsg}\\n\\n\`);
    setTimeout(() => jobs.delete(jobId), 60_000);
  });

  return { jobId };
}

`;

  // Insert before Request dispatcher
  serverCode = serverCode.replace('// ─── Request dispatcher ───────────────────────────────────────────────────────', handlerCode + '// ─── Request dispatcher ───────────────────────────────────────────────────────');

  // Insert routes
  const routesCode = `
    if (path === '/api/learning/status' && method === 'GET') {
      return sendJson(res, await handleLearningStatus());
    }
    if (path === '/api/learning/scaffold' && method === 'POST') {
      const body = await readBody(req);
      return sendJson(res, await handleLearningScaffold(body));
    }
`;
  serverCode = serverCode.replace("if (path === '/api/status' && method === 'GET') {", routesCode + "    if (path === '/api/status' && method === 'GET') {");

  fs.writeFileSync(serverFile, serverCode);
  console.log('Patched server.mjs');
}

const indexFile = 'scripts/dashboard/index.html';
let indexCode = fs.readFileSync(indexFile, 'utf8');

if (!indexCode.includes('Learning Center')) {
  // Add Tabs to header
  const tabsHtml = `
  <div id="nav-tabs" style="display:flex;gap:15px;margin-left:20px;">
    <button class="btn btn-primary" id="tab-research" onclick="switchTab('research')">Research</button>
    <button class="btn" id="tab-learning" onclick="switchTab('learning')">Learning Center</button>
  </div>
`;
  indexCode = indexCode.replace('<h1>My_Data Operator Dashboard</h1>', '<h1>My_Data Dashboard</h1>' + tabsHtml);

  // Wrap existing main
  indexCode = indexCode.replace('<div id="main">', '<div id="main-research">');
  indexCode = indexCode.replace('</body>', `
</div>
<div id="main-learning" style="display:none; padding:14px 16px;">
  <div class="panel" style="margin-bottom:14px;">
    <div class="panel-header"><span class="panel-title">Learning Status</span></div>
    <div class="panel-body" style="display:flex; justify-content:space-between; align-items:center;">
      <div>
        <div style="font-size:14px;font-weight:bold;" id="learning-state">Loading...</div>
      </div>
      <div>
        <button class="btn btn-primary" onclick="scaffoldLearning()">Scaffold Daily Setup</button>
      </div>
    </div>
  </div>

  <div class="panel" id="learning-terminal">
    <div class="panel-header"><span class="panel-title">Agent Output</span></div>
    <div class="panel-body" id="learning-terminal-output" style="font-family:monospace;font-size:12px;background:#080b10;padding:10px;height:200px;overflow-y:auto;white-space:pre-wrap;">
    </div>
  </div>
</div>

<script>
function switchTab(tab) {
  document.getElementById('main-research').style.display = (tab === 'research') ? 'flex' : 'none';
  document.getElementById('main-learning').style.display = (tab === 'learning') ? 'block' : 'none';
  document.getElementById('tab-research').className = (tab === 'research') ? 'btn btn-primary' : 'btn';
  document.getElementById('tab-learning').className = (tab === 'learning') ? 'btn btn-primary' : 'btn';
  if (tab === 'learning') loadLearningStatus();
}

async function loadLearningStatus() {
  try {
    const res = await fetch('/api/learning/status');
    const data = await res.json();
    document.getElementById('learning-state').innerText = \`State: \${data.status} (Date: \${data.date})\`;
  } catch (e) {
    document.getElementById('learning-state').innerText = 'Error loading status';
  }
}

async function scaffoldLearning() {
  const out = document.getElementById('learning-terminal-output');
  out.innerHTML = 'Starting...\\n';
  try {
    const res = await fetch('/api/learning/scaffold', { method: 'POST', body: JSON.stringify({}) });
    const data = await res.json();
    if (data.jobId) {
      const src = new EventSource(\`/api/stream/\${data.jobId}\`);
      src.addEventListener('line', e => {
        const lineData = JSON.parse(e.data);
        out.innerHTML += lineData.text + '\\n';
        out.scrollTop = out.scrollHeight;
      });
      src.addEventListener('exit', () => {
        src.close();
        out.innerHTML += '\\nDone.\\n';
        loadLearningStatus();
      });
    }
  } catch (err) {
    out.innerHTML += 'Error: ' + err.message;
  }
}
</script>
</body>`);

  fs.writeFileSync(indexFile, indexCode);
  console.log('Patched index.html');
}
EOF
