import fs from 'fs';

const serverFile = 'scripts/dashboard/server.mjs';
let serverCode = fs.readFileSync(serverFile, 'utf8');

// 1. Add writeFile to fs/promises import if not there
if (serverCode.includes("import { readFile, readdir, stat } from 'fs/promises';")) {
  serverCode = serverCode.replace(
    "import { readFile, readdir, stat } from 'fs/promises';",
    "import { readFile, readdir, stat, writeFile } from 'fs/promises';"
  );
} else if (!serverCode.includes("writeFile")) {
  serverCode = serverCode.replace(
    "from 'fs/promises';",
    ", writeFile } from 'fs/promises';"
  );
}

// 2. Add API handlers for wildcard
if (!serverCode.includes('handleActiveWildcard')) {
  const wildcardHandlers = `
async function handleActiveWildcard() {
  const date = new Date().toISOString().slice(0, 10);
  const wildcardsDir = join(getVaultRoot(), '11_Learning', '03_Wildcards');
  if (!existsSync(wildcardsDir)) return { error: 'No wildcards dir' };
  const files = await readdir(wildcardsDir);
  const todayFile = files.find(f => f.startsWith(date) && f.endsWith('Wildcard.md'));
  if (!todayFile) return { error: 'No wildcard for today' };

  const content = await readFile(join(wildcardsDir, todayFile), 'utf8');
  return { filename: todayFile, content };
}

async function handleSaveWildcard(body) {
  const { filename, content } = body;
  if (!filename || !content) return { error: 'Missing data' };
  const filePath = join(getVaultRoot(), '11_Learning', '03_Wildcards', filename);
  if (!existsSync(filePath)) return { error: 'File not found' };
  await writeFile(filePath, content, 'utf8');
  return { success: true };
}
`;

  serverCode = serverCode.replace('async function handleLearningScaffold', wildcardHandlers + '\nasync function handleLearningScaffold');

  const wildcardRoutes = `
    if (path === '/api/learning/active-wildcard' && method === 'GET') {
      return sendJson(res, await handleActiveWildcard());
    }
    if (path === '/api/learning/save-wildcard' && method === 'POST') {
      const body = await readBody(req);
      return sendJson(res, await handleSaveWildcard(body));
    }
`;
  serverCode = serverCode.replace("if (path === '/api/learning/scaffold' && method === 'POST') {", wildcardRoutes + "    if (path === '/api/learning/scaffold' && method === 'POST') {");

  fs.writeFileSync(serverFile, serverCode);
  console.log('Patched server.mjs for Phase 2');
} else {
  console.log('server.mjs already patched for Phase 2');
}

const indexFile = 'scripts/dashboard/index.html';
let indexCode = fs.readFileSync(indexFile, 'utf8');

if (!indexCode.includes('wildcard-editor')) {
  const editorHtml = `
  <div id="wildcard-editor" style="display:none; flex-direction:row; gap:14px;">
    <!-- Left panel: Read-only resources -->
    <div class="panel" style="flex:1;">
      <div class="panel-header"><span class="panel-title">Wildcard Context & Resources</span></div>
      <div class="panel-body" id="wildcard-resources" style="font-family:var(--font);font-size:13px;height:600px;overflow-y:auto;white-space:pre-wrap;line-height:1.6;">
        Loading resources...
      </div>
    </div>
    <!-- Right panel: Editor -->
    <div class="panel" style="flex:1;">
      <div class="panel-header"><span class="panel-title">Synthesis Editor</span></div>
      <div class="panel-body" style="display:flex;flex-direction:column;gap:10px;">
        <textarea id="wildcard-content" style="width:100%;height:560px;background:#080b10;color:var(--text);border:1px solid var(--border);padding:10px;font-family:var(--mono);font-size:12px;"></textarea>
        <div style="display:flex; justify-content:space-between; align-items:center;">
          <button class="btn btn-primary" onclick="saveWildcard()">Save Wildcard</button>
          <div id="save-status" style="font-size:11px;color:var(--clear);"></div>
        </div>
      </div>
    </div>
  </div>
`;

  indexCode = indexCode.replace('<div class="panel" id="learning-terminal">', editorHtml + '\n  <div class="panel" id="learning-terminal">');

  const jsUpdates = `
let currentWildcardFilename = '';
async function loadWildcard() {
  try {
    const res = await fetch('/api/learning/active-wildcard');
    const data = await res.json();
    if (data.content) {
      currentWildcardFilename = data.filename;
      document.getElementById('wildcard-content').value = data.content;

      // Parse out the "Resources:" sections for the left panel to make them easy to read
      let resourcesText = '';
      const lines = data.content.split('\\n');
      let inResources = false;
      let currentSection = '';

      for (const line of lines) {
        if (line.startsWith('## ')) {
          currentSection = line;
        }
        if (line.startsWith('**Resources:**')) {
          inResources = true;
          resourcesText += '\\n\\n' + currentSection + '\\n' + line + '\\n';
          continue;
        }
        if (inResources && line.startsWith('### Your Output')) {
          inResources = false;
        }
        if (inResources) {
          resourcesText += line + '\\n';
        }
      }

      if (!resourcesText.trim()) {
         resourcesText = "Check the editor on the right for full content.";
      }
      document.getElementById('wildcard-resources').innerText = resourcesText.trim();
    } else {
      document.getElementById('wildcard-resources').innerText = 'No active wildcard file found for today.';
    }
  } catch (e) {
    console.error(e);
  }
}

async function saveWildcard() {
  const content = document.getElementById('wildcard-content').value;
  document.getElementById('save-status').innerText = 'Saving...';
  try {
    const res = await fetch('/api/learning/save-wildcard', {
      method: 'POST',
      body: JSON.stringify({ filename: currentWildcardFilename, content })
    });
    if (res.ok) {
      document.getElementById('save-status').innerText = 'Saved at ' + new Date().toLocaleTimeString();
    } else {
      document.getElementById('save-status').innerText = 'Error saving';
    }
  } catch(e) {
    document.getElementById('save-status').innerText = 'Network error';
  }
}
`;

  // Inject JS functions
  indexCode = indexCode.replace('async function loadLearningStatus() {', jsUpdates + '\nasync function loadLearningStatus() {');

  // Update loadLearningStatus to toggle visibility
  const statusUpdate = `
    document.getElementById('learning-state').innerText = \`State: \${data.status} (Date: \${data.date})\`;
    if (data.status === 'Wildcard Active') {
      document.getElementById('wildcard-editor').style.display = 'flex';
      document.getElementById('learning-terminal').style.display = 'none';
      loadWildcard();
    } else {
      document.getElementById('wildcard-editor').style.display = 'none';
      document.getElementById('learning-terminal').style.display = 'block';
    }
`;
  indexCode = indexCode.replace("document.getElementById('learning-state').innerText = `State: ${data.status} (Date: ${data.date})`;", statusUpdate);

  fs.writeFileSync(indexFile, indexCode);
  console.log('Patched index.html for Phase 2');
} else {
  console.log('index.html already patched for Phase 2');
}

import fs from 'fs';

const serverFile = 'scripts/dashboard/server.mjs';
let serverCode = fs.readFileSync(serverFile, 'utf8');

// Add API handlers for active check
if (!serverCode.includes('handleActiveCheck')) {
  const checkHandlers = `
async function handleActiveCheck(req) {
  const url = new URL(req.url, 'http://localhost');
  const type = url.searchParams.get('type') || 'daily';

  const date = new Date().toISOString().slice(0, 10);
  const checksDir = join(getVaultRoot(), '11_Learning', '02_Checks');
  if (!existsSync(checksDir)) return { error: 'No checks dir' };

  const files = await readdir(checksDir);
  let targetFile;

  if (type === 'daily') {
    targetFile = files.find(f => f.startsWith(date) && f.endsWith('Daily Check.md'));
  } else {
    targetFile = files.find(f => f.startsWith(date) && f.endsWith('Knowledge Check.md'));
  }

  if (!targetFile) return { error: 'No active check found' };

  const content = await readFile(join(checksDir, targetFile), 'utf8');
  return { filename: targetFile, content };
}

async function handleSaveCheck(body) {
  const { filename, content } = body;
  if (!filename || !content) return { error: 'Missing data' };
  const filePath = join(getVaultRoot(), '11_Learning', '02_Checks', filename);
  if (!existsSync(filePath)) return { error: 'File not found' };
  await writeFile(filePath, content, 'utf8');
  return { success: true };
}
`;

  serverCode = serverCode.replace('async function handleLearningScaffold', checkHandlers + '\nasync function handleLearningScaffold');

  const checkRoutes = `
    if (path === '/api/learning/active-check' && method === 'GET') {
      return sendJson(res, await handleActiveCheck(req));
    }
    if (path === '/api/learning/save-check' && method === 'POST') {
      const body = await readBody(req);
      return sendJson(res, await handleSaveCheck(body));
    }
`;
  serverCode = serverCode.replace("if (path === '/api/learning/active-wildcard' && method === 'GET') {", checkRoutes + "    if (path === '/api/learning/active-wildcard' && method === 'GET') {");

  fs.writeFileSync(serverFile, serverCode);
  console.log('Patched server.mjs for Phase 3');
} else {
  console.log('server.mjs already patched for Phase 3');
}

const indexFile = 'scripts/dashboard/index.html';
let indexCode = fs.readFileSync(indexFile, 'utf8');

if (!indexCode.includes('check-editor')) {
  const checkHtml = `
  <div id="check-editor" style="display:none; flex-direction:row; gap:14px; margin-bottom:14px;">
    <!-- Left panel: Read-only resources -->
    <div class="panel" style="flex:1;">
      <div class="panel-header">
        <span class="panel-title" id="check-title">Knowledge Lock</span>
      </div>
      <div class="panel-body" id="check-resources" style="font-family:var(--font);font-size:13px;height:400px;overflow-y:auto;white-space:pre-wrap;line-height:1.6;">
        Loading prompt...
      </div>
    </div>
    <!-- Right panel: Editor -->
    <div class="panel" style="flex:1;">
      <div class="panel-header"><span class="panel-title">Your Answer</span></div>
      <div class="panel-body" style="display:flex;flex-direction:column;gap:10px;">
        <textarea id="check-content" style="width:100%;height:360px;background:#080b10;color:var(--text);border:1px solid var(--border);padding:10px;font-family:var(--mono);font-size:12px;"></textarea>
        <div style="display:flex; justify-content:space-between; align-items:center;">
          <button class="btn btn-primary" onclick="saveCheck()">Save Answer</button>
          <div id="check-save-status" style="font-size:11px;color:var(--clear);"></div>
        </div>
      </div>
    </div>
  </div>
`;

  indexCode = indexCode.replace('<div id="wildcard-editor"', checkHtml + '\n  <div id="wildcard-editor"');

  const jsUpdates = `
let currentCheckFilename = '';
async function loadCheck(type = 'daily') {
  try {
    const res = await fetch('/api/learning/active-check?type=' + type);
    const data = await res.json();
    if (data.content) {
      currentCheckFilename = data.filename;

      document.getElementById('check-title').innerText = type === 'daily' ? 'Surface Check (Knowledge Lock)' : 'Advanced Knowledge Check';

      // Extract the prompt and hints for the left panel
      let resourcesText = '';
      const lines = data.content.split('\\n');
      let capture = false;
      let inAnswer = false;

      // Find the answer section
      let answerSection = '';

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];

        if (line.startsWith('## Prompt') || line.startsWith('## Hints')) {
          capture = true;
          resourcesText += '\\n\\n**' + line.replace('## ', '') + '**\\n';
